components.css:
*{-webkit-tap-highlight-color: transparent;}

/* === Background Color === */

.background {
  width: 100%;
  height: 100%;
  background: black;
}

/* === Video === */

.video {
  width: 100%;
  height: 100%;
  left: 50%;
  top: 50%;
  transform: translate(-50%,-50%);
  max-width: unset !important;

  .vertical & {
    width: 100%;
    height: 100%;
  }
}

video {
  object-position: center !important;
}

.video div:first-child {
  padding-top: 0 !important;
  width: 100%;
  height: 100% !important;
}

/* === Video progress === */

.video-progress-container {
  background-color: #dddddd !important;
  .video-progress{
    background-color: crimson !important;
  }
}

/* === Replay container === */

.replay-container-backup {
  width: 100%;
  height: 100%;
  position: absolute;
  top: 0;
  left: 0;
  z-index: -1;
}

.replay-container-backup,
.replay-container {
  background-size: contain !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
  & svg {
    width: 30px !important;
    height: 30px !important;
  }
}

.replay-container {
  background-image: url({{replay.jpg}}) !important;
}


/* == Animations == */

.background, .video, .video-progress-container {
  opacity: 0;
  transition: .3s;

  .entering & {
    opacity: 0;
  }

  .entered & {
    opacity: 1;
  }

  .exiting & {
    opacity: 0;
  }
}

